INSERT INTO services (id, slug, icon, title_en, title_vi, title_zh_cn, title_zh_tw, description_en, description_vi, description_zh_cn, description_zh_tw, full_description_en, full_description_vi, full_description_zh_cn, full_description_zh_tw, ideal_for_en, ideal_for_vi, ideal_for_zh_cn, ideal_for_zh_tw, what_we_deliver_en, what_we_deliver_vi, what_we_deliver_zh_cn, what_we_deliver_zh_tw, sort_order, is_published, featured, created_at, updated_at) VALUES (13, 'meta-ads', 'ph-stack', 'Meta Ads Architecture ', 'Meta Ads Architecture', 'Meta Ads Architecture', 'Meta Ads Architecture', 'We structure ad accounts built for machine learning. Moving away from manual tweaking to dynamic creative testing and broad audience scaling on Facebook and Instagram.', 'Advanced audience structuring, dynamic creative testing, and machine-learning-friendly campaign setups for maximum ROAS.', 'Advanced audience structuring, dynamic creative testing, and machine-learning-friendly campaign setups for maximum ROAS.', 'Advanced audience structuring, dynamic creative testing, and machine-learning-friendly campaign setups for maximum ROAS.', '', 'We structure ad accounts built for machine learning. Moving away from manual tweaking to dynamic creative testing and broad audience scaling on Facebook and Instagram.', 'We structure ad accounts built for machine learning. Moving away from manual tweaking to dynamic creative testing and broad audience scaling on Facebook and Instagram.', 'We structure ad accounts built for machine learning. Moving away from manual tweaking to dynamic creative testing and broad audience scaling on Facebook and Instagram.', 'D2C Brands\nSaaS Companies\nAgencies\nE-commerce Sellers', 'Thương hiệu Thương mại điện tử\\nCác công ty SaaS\\nCác cơ quan\\nDropshipping', '电子商务品牌\\nSaaS公司\\n代理商\\n一件代发', '電子商務品牌\\nSaaS公司\\n代理商\\n一件代發', 'Account Restructuring - Consolidating campaigns to test algorithms faster and cut learning phase.\nCreative Testing Protocol - Systematic testing of hooks, formats, and copy to find statistical winners.\nCAPI Integration - Flawless Conversion API setup to counter iOS updates and restore data visibility.\nScaling Mechanics - Vertical and horizontal budget scaling rules without breaking ROI.', 'Kiến trúc Chiến dịch Nâng cao\\nKiểm tra Sáng tạo Động\\nTối ưu hóa Học máy\\nPhân tích Hiệu suất Thời gian thực\\nCác bài đánh giá Chiến lược hàng tháng', '高级活动架构\\n动态创意测试\\n机器学习优化\\n实时性能分析\\n月度战略审查', '高級活動架構\\n動態創意測試\\n機器學習優化\\n實時性能分析\\n月度戰略審查', 1, true, true, '2026-03-17T07:17:35.919Z', '2026-03-18T03:29:34.852Z');
INSERT INTO services (id, slug, icon, title_en, title_vi, title_zh_cn, title_zh_tw, description_en, description_vi, description_zh_cn, description_zh_tw, full_description_en, full_description_vi, full_description_zh_cn, full_description_zh_tw, ideal_for_en, ideal_for_vi, ideal_for_zh_cn, ideal_for_zh_tw, what_we_deliver_en, what_we_deliver_vi, what_we_deliver_zh_cn, what_we_deliver_zh_tw, sort_order, is_published, featured, created_at, updated_at) VALUES (14, 'google-ads', 'ph-google-logo', 'Google Performance Max', 'Google Performance Max', 'Google Performance Max', 'Google Performance Max', 'Intent-based search campaigns, high-converting shopping feeds, and full-funnel PMax strategies to capture high-value demand.', 'Intent-based search campaigns, high-converting shopping feeds, and full-funnel PMax strategies to capture high-value demand.', 'Intent-based search campaigns, high-converting shopping feeds, and full-funnel PMax strategies to capture high-value demand.', 'Intent-based search campaigns, high-converting shopping feeds, and full-funnel PMax strategies to capture high-value demand.', 'Capture high-intent demand. We architect precise search campaigns and deploy highly optimized Performance Max builds to dominate search engine results.', 'Capture high-intent demand. We architect precise search campaigns and deploy highly optimized Performance Max builds to dominate search engine results.', 'Capture high-intent demand. We architect precise search campaigns and deploy highly optimized Performance Max builds to dominate search engine results.', 'Capture high-intent demand. We architect precise search campaigns and deploy highly optimized Performance Max builds to dominate search engine results.', 'D2C & E-commerce\nLocal Lead Gen\nInfo-Products', 'Các công ty B2B\\nDịch vụ Chi phí cao\\nDoanh nghiệp Địa phương\\nSản phẩm SaaS', '企业对企业公司\\n高票服务\\n本地企业\\nSaaS产品', '企業對企業公司\\n高票服務\\n本地企業\\nSaaS產品', 'Performance Max Setup - Omnichannel campaigns optimized for conversions across Search, Display, YouTube, and Gmail.\nAudience Targeting - Custom audiences from your data, customer match, and lookalike modeling.\nFeed Optimization - Structuring product feeds for maximum relevance and performance in Google Ads.\nSmart Bidding - Automated bid strategies powered by ML to maximize conversions within your CPA target.', 'Chiến lược Performance Max\\nTối ưu hóa Chiến dịch Tìm kiếm\\nQuản lý Nguồn cấp Shopping\\nTối ưu hóa Tỷ lệ Chuyển đổi\\nBáo cáo Tăng trưởng Hàng quý', '性能最大化策略\\n搜索活动优化\\n购物信息流管理\\n转化率优化\\n季度增长报告', '性能最大化策略\\n搜索活動優化\\n購物信息流管理\\n轉化率優化\\n季度增長報告', 2, true, true, '2026-03-17T07:17:35.952Z', '2026-03-17T07:17:35.952Z');
INSERT INTO services (id, slug, icon, title_en, title_vi, title_zh_cn, title_zh_tw, description_en, description_vi, description_zh_cn, description_zh_tw, full_description_en, full_description_vi, full_description_zh_cn, full_description_zh_tw, ideal_for_en, ideal_for_vi, ideal_for_zh_cn, ideal_for_zh_tw, what_we_deliver_en, what_we_deliver_vi, what_we_deliver_zh_cn, what_we_deliver_zh_tw, sort_order, is_published, featured, created_at, updated_at) VALUES (15, 'tiktok-ads', 'ph-tiktok-logo', 'TikTok Shop & Growth', 'TikTok Shop & Growth', 'TikTok Shop & Growth', 'TikTok Shop & Growth', 'Viral content creation strategies, influencer seeding, and aggressive TikTok ad scaling for modern D2C and e-commerce brands.', 'Viral content creation strategies, influencer seeding, and aggressive TikTok ad scaling for modern D2C and e-commerce brands.', 'Viral content creation strategies, influencer seeding, and aggressive TikTok ad scaling for modern D2C and e-commerce brands.', 'Viral content creation strategies, influencer seeding, and aggressive TikTok ad scaling for modern D2C and e-commerce brands.', 'Stop making ads. Start making TikToks. We handle end-to-end TikTok growth, from creator sourcing and brief writing to aggressive media buying and Shop optimization.', 'Stop making ads. Start making TikToks. We handle end-to-end TikTok growth, from creator sourcing and brief writing to aggressive media buying and Shop optimization.', 'Stop making ads. Start making TikToks. We handle end-to-end TikTok growth, from creator sourcing and brief writing to aggressive media buying and Shop optimization.', 'Stop making ads. Start making TikToks. We handle end-to-end TikTok growth, from creator sourcing and brief writing to aggressive media buying and Shop optimization.', 'Fashion & Beauty Brands\nTrending Product Sellers\nCreator-led Businesses', 'Thương hiệu Thời trang\\nSản phẩm Sắc đẹp\\nSản phẩm Xu hướng\\nNền kinh tế Sáng tạo', '时尚品牌\\n美容产品\\n流行商品\\n创作者经济', '時尚品牌\\n美容產品\\n流行商品\\n創作者經濟', 'Branded Content - Creator partnerships and branded hashtag challenges that feel native to TikTok culture.\nDirect Response - Short-form video ads optimized for conversions and impulse purchases on TikTok Shop.\nCommunity Building - Organic growth hacks and community engagement strategies that drive loyal followers.\nTikTok Shop Setup - Integration and optimization of TikTok Shop for seamless commerce experiences.', 'Tối ưu hóa Danh sách Cửa hàng\\nChiến lược Nội dung Viral\\nThiết lập Hợp tác Người có ảnh hưởng\\nQuản lý Cộng đồng\\nPhân tích TikTok Hàng tháng', '商店列表优化\\n病毒内容策略\\n影响者合作设置\\n社区管理\\n每月TikTok分析', '商店列表優化\\n病毒內容策略\\n影響者合作設置\\n社區管理\\n每月TikTok分析', 3, true, true, '2026-03-17T07:17:35.984Z', '2026-03-17T07:17:35.984Z');
